using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 removed Cosmos DB indexing support.
            // modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
            // Indexes must be managed via Azure Portal / IaC instead.

            // Breaking change 2: Discriminator property renamed from "Discriminator" to "$type".
            // Preserve compat with existing documents that use the old property name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 3: Id format changed from "EntityType|Key" to just "Key".
            // Preserve compat with existing documents that use the old "Blog|1" format.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }
}

// Generates ids in the legacy "Blog|{key}" format for backward compatibility.
